use std::collections::VecDeque;
use std::cmp::min;

// Helper function to check if a path exists from source to target using at most K heavy edges 
// given a specific threshold. This uses 0-1 BFS.
fn can_reach(
    n: usize,
    adj: &Vec<Vec<(usize, i64)>>,
    source: usize,
    target: usize,
    k: i64,
    threshold: i64,
) -> bool {
    if source == target {
        return true;
    }

    // dist[i] stores the minimum number of heavy edges required to reach node i.
    // Since K is the max allowed, we use K + 1 as infinity.
    let k_limit = k + 1;
    let mut dist: Vec<i64> = vec![k_limit; n];

    let mut deque: VecDeque<usize> = VecDeque::new();

    dist[source] = 0;
    deque.push_front(source);

    while let Some(u) = deque.pop_front() {
        let current_heavy_count = dist[u];

        if current_heavy_count > k {
            continue;
        }

        if u == target {
            // Optimization: If we reached target, since 0-1 BFS explores in increasing order of cost, 
            // this is the shortest path in terms of heavy edges.
            return true; 
        }

        for &(v, weight) in adj[u].iter() {
            let cost = if weight > threshold { 1 } else { 0 };
            let new_heavy_count = current_heavy_count + cost;

            if new_heavy_count <= k && new_heavy_count < dist[v] {
                dist[v] = new_heavy_count;

                if cost == 0 {
                    deque.push_front(v);
                } else {
                    deque.push_back(v);
                }
            }
        }
    }

    // If the loop finishes and we haven't returned true, check the final distance.
    dist[target] <= k
}


