        let u = edge[0];
        let v = edge[1];
        let w = edge[2];
        adj[u as usize].push((v, w));
        adj[v as usize].push((u, w));
        weights.push(w);
    }

    // Check function: Can we reach target from source using at most K heavy edges for a given threshold T?
    let can_reach = |threshold: i64| -> bool {
        let n_usize = n as usize;
        let k_limit = k;

        // D[i] stores the minimum number of heavy edges required to reach node i.
        // Initialize to K + 1 (effectively infinity within our constraint)
        let mut d: Vec<i64> = vec![k_limit + 1; n_usize];
        d[source as usize] = 0;

        // O(N^2) Dijkstra implementation using array scanning for minimum distance node
        let mut visited: Vec<bool> = vec![false; n_usize];

        for _ in 0..n {
            // 1. Find the unvisited node u with the minimum distance D[u]
            let mut u_idx = n_usize;
            let mut min_dist = k_limit + 1;

